const path = "~/contacts.yaml"
const text = await space.api.fileRead(path, "utf8")
let data
try {
  data = space.utils.yaml.parse(text)
} catch (e) {
  return `Failed to parse YAML: ${e.message}`
}

function replaceInObject(obj) {
  if (Array.isArray(obj)) return obj.map(replaceInObject)
  if (obj && typeof obj === "object") {
    for (const [k, v] of Object.entries(obj)) {
      if (typeof v === "string" && v === "mr_kowalski") {
        obj[k] = "John Ronald Kowalski"
      } else if (v && typeof v === "object") {
        obj[k] = replaceInObject(v)
      }
    }
  }
  return obj
}

const updated = replaceInObject(data)
const out = space.utils.yaml.stringify(updated)
await space.api.fileWrite(path, out, "utf8")
return "Updated ~/contacts.yaml"

